function hideMiniPlayer() {
    document.getElementById('miniPlayer').style.display = 'none';
    document.getElementById('sectionsButton').classList.remove('player-active');
}

function stopMusic() {
    if (currentMusic) {
        currentMusic.pause();
        currentMusic.currentTime = 0;
        isPlaying = false;
        updatePlayingStatus('Ничего');
        
        // СБРОС МУЗЫКАЛЬНОЙ СЕССИИ 🔄
        window.musicSessionStart = null;
        if (window.musicTimeInterval) {
            clearInterval(window.musicTimeInterval);
            window.musicTimeInterval = null;
        }
    }
}

let currentMusic = null;
let isPlaying = false;

function toggleLoop() {
    if (currentMusic) {
        isLooping = !isLooping;
        currentMusic.loop = isLooping;
        
        let loopBtn = document.getElementById('loopBtn');
        if (isLooping) {
            loopBtn.style.color = '#ff6b6b';
        } else {
            loopBtn.style.color = 'white';
        }
    }
}

function playTrack(filename, title) {
    if (currentMusic) {
        currentMusic.pause();
        currentMusic.currentTime = 0;
    }
    
    currentMusic = new Audio(filename);
    currentMusic.volume = 0.5;
    currentMusic.loop = isLooping;
    currentMusic.play();
    isPlaying = true;
    
    updatePlayingStatus(title);
    showMiniPlayer(title);
    
    currentMusic.addEventListener('ended', function() {
        if (!isLooping) {
            // ТРЕКИНГ ПО ЗАВЕРШЕНИЮ ТРЕКА! 🏆
            trackMusicProgress(filename, currentMusic.duration * 1000, true); // duration в миллисекундах
            
            isPlaying = false;
            updatePlayingStatus('Ничего');
            hideMiniPlayer();
        }
    });
    
    // ТРЕКИНГ ВРЕМЕНИ СЕССИИ (для ночного диджея) 🕐
    if (!window.musicSessionStart) {
        window.musicSessionStart = Date.now();
    }
    
    // ПРОВЕРКА НОЧНОГО ДИДЖЕЯ
    if (!window.musicTimeInterval) {
        window.musicTimeInterval = setInterval(() => {
            if (currentMusic && isPlaying) {
                let sessionTime = Date.now() - window.musicSessionStart;
                if (sessionTime >= 1800000) { // 30 минут РЕАЛЬНОГО времени
                    unlockAchievement('night_dj');
                    clearInterval(window.musicTimeInterval);
                }
            }
        }, 10000);
    }
}

function closeMiniPlayer() {
    stopMusic();
    hideMiniPlayer();
}

function closeMusicCatalog() {
    document.getElementById('musicCatalog').style.display = 'none';
}

function stopMusic() {
    if (currentMusic) {
        currentMusic.pause();
        currentMusic.currentTime = 0;
        isPlaying = false;
        updatePlayingStatus('Ничего');
    }
}

function updatePlayingStatus(title) {
    let element = document.getElementById('currentTrack');
    if (element) {
        element.textContent = title;
    }
    
    // Обновляем мини-плеер тоже
    let miniPlayer = document.getElementById('miniTrackName');
    if (miniPlayer) {
        miniPlayer.textContent = title;
    }
}

