function buyBossUpgrade(type) {
    if (bossClicks >= bossUpgrades[type].cost) {
        bossClicks -= bossUpgrades[type].cost;
        bossUpgrades[type].level++;
        
        if (type === 'damage') {
            bossDamage++;
            bossUpgrades[type].cost = Math.floor(bossUpgrades[type].cost * 1.5);
        }
        else if (type === 'autoClick') {
            bossUpgrades[type].dps += 1;
            bossUpgrades[type].cost = Math.floor(bossUpgrades[type].cost * 2);
            startBossAutoClick();
        }
        else if (type === 'critChance') {
            bossUpgrades[type].chance += 10;
            bossUpgrades[type].cost = Math.floor(bossUpgrades[type].cost * 3);
        }
        
        updateBossUI();
    }
}

function startBossAutoClick() {
    if (!window.bossAutoClickInterval && bossUpgrades.autoClick.dps > 0) {
        window.bossAutoClickInterval = setInterval(() => {
            if (bossHP > 0) {
                bossHP -= bossUpgrades.autoClick.dps;
                updateBossUI();
                if (bossHP <= 0) {
                    // АЧИВОЧНЫЙ ТРИГГЕР! ⚔️
                    trackGameProgress('first_game', 'killed_1x1x1x1');
                    
                    alert('🎉 1x1x1x1 УБИТ! ПОБЕДА!');
                    resetBossGame();
                }
            }
        }, 1000);
    }
}

