let autoClickInterval = null;
let hasAutoClick = false;

function clickForMoney() {
    cardMoney += clickPower;
    totalClicks++;
    
    updateUI();
    createClickAnimation();
}

function createClickAnimation() {
    let clickArea = document.getElementById('clickerArea');
    let animation = document.createElement('div');
    animation.textContent = `+${clickPower}`;
    animation.style.cssText = `
        position: absolute;
        left: ${Math.random() * 100 + 50}px;
        top: 50px;
        color: #FFD700;
        font-weight: bold;
        font-size: 20px;
        pointer-events: none;
        z-index: 1000;
        animation: floatUp 1s ease-out forwards;
    `;
    
    clickArea.appendChild(animation);
    
    setTimeout(() => animation.remove(), 1000);
}

// CSS анимация для летящих монет
if (!document.getElementById('cardGameCSS')) {
    let style = document.createElement('style');
    style.id = 'cardGameCSS';
    style.textContent = `
        @keyframes floatUp {
            0% { opacity: 1; transform: translateY(0px); }
            100% { opacity: 0; transform: translateY(-50px); }
        }
        
        @keyframes cardGlow {
            0%, 100% { box-shadow: 0 0 20px currentColor; }
            50% { box-shadow: 0 0 40px currentColor, 0 0 60px currentColor; }
        }
        
        .rare-card {
            animation: cardGlow 2s infinite;
        }
        
        @keyframes confetti {
            0% { transform: translateY(0) rotate(0deg); opacity: 1; }
            100% { transform: translateY(-200px) rotate(360deg); opacity: 0; }
        }
    `;
    document.head.appendChild(style);
}

function buyUpgrade(type) {
    if (type === 'power') {
        let cost = 100 * clickPower;
        if (cardMoney >= cost) {
            cardMoney -= cost;
            clickPower++;
            updateUI();
            alert(`⚡ Сила клика увеличена! Теперь +${clickPower} за клик`);
        } else {
            alert('Недостаточно монет!');
        }
    } else if (type === 'auto') {
        if (!hasAutoClick && cardMoney >= 500) {
            cardMoney -= 500;
            hasAutoClick = true;
            startAutoClick();
            updateUI();
            alert('🤖 Авто-клик активирован!');
        } else if (hasAutoClick) {
            alert('Авто-клик уже куплен!');
        } else {
            alert('Недостаточно монет!');
        }
    }
}

function startAutoClick() {
    if (!autoClickInterval) {
        autoClickInterval = setInterval(() => {
            cardMoney += Math.floor(clickPower / 2);
            updateUI();
        }, 1000);
    }
}

function updateUI() {
    document.getElementById('cardMoney').textContent = cardMoney;
    document.getElementById('cardsCollected').textContent = Object.keys(collection).length;
    document.getElementById('totalClicks').textContent = totalClicks;
    document.getElementById('clickPower').textContent = clickPower;
    
    // Обновляем цены апгрейдов
    let powerBtn = document.getElementById('powerUpgrade');
    if (powerBtn) {
        powerBtn.textContent = `⚡ +1 Сила клика (${100 * clickPower} монет)`;
    }
    
    let autoBtn = document.getElementById('autoUpgrade');
    if (autoBtn && hasAutoClick) {
        autoBtn.textContent = '🤖 Авто-клик (КУПЛЕН)';
        autoBtn.disabled = true;
        autoBtn.style.background = '#666';
    }
}

function getRandomCard(packType = 'basic') {

let random = Math.random() * 100;
    
    if (packType === 'legendary') {
        // СБАЛАНСИРОВАННЫЕ ШАНСЫ! 💎
        if (random < 79.5) return getCardByRarity('s');      // 79.5% - S
        if (random < 99.5) return getCardByRarity('splus');  // 20% - S+  
        return getCardByRarity('ssplus');                    // 0.5% - SS+
    }

    // Простая и понятная логика
    if (random < 35) return getCardByRarity('common');
    if (random < 60) return getCardByRarity('uncommon'); 
    if (random < 75) return getCardByRarity('rare');
    if (random < 85) return getCardByRarity('superrare');
    if (random < 91) return getCardByRarity('epic');
    if (random < 95) return getCardByRarity('epicplus');
    if (random < 97.5) return getCardByRarity('mythic');
    if (random < 99) return getCardByRarity('mythicplus');
    if (random < 99.7) return getCardByRarity('legendary');
    if (random < 99.9) return getCardByRarity('legendaryplus');
    if (random < 99.98) return getCardByRarity('s');
    if (random < 99.999) return getCardByRarity('splus');
    return getCardByRarity('ssplus');
}

function getCardByRarity(rarity) {
    let cards = cardDatabase.filter(card => card.rarity === rarity);
    
    // ЗАЩИТА: если карт с такой редкостью нет, возвращаем обычную
    if (cards.length === 0) {
        console.warn(`Нет карт с редкостью: ${rarity}`);
        return cardDatabase.find(card => card.rarity === 'common');
    }
    
    return cards[Math.floor(Math.random() * cards.length)];
}

function openPack(packType) {
    let cost, cardsCount;
    
    switch(packType) {
        case 'basic':
            cost = 50;
            cardsCount = 10;
            break;
        case 'premium':
            cost = 200;
            cardsCount = 10;
            break;
        case 'mega':
            cost = 500;
            cardsCount = 20;
            break;
        case 'legendary':
            cost = 100000;
            cardsCount = 1;
            break;
    }
    
    if (cardMoney < cost) {
        alert('Недостаточно монет!');
        return;
    }
    
    cardMoney -= cost;
    updateUI();
    
    // АЧИВОЧНЫЕ ТРИГГЕРЫ! 🔥
    trackPackOpening();
    
     let resultDiv = document.getElementById('cardResult');
    
    if (packType === 'legendary') {
        // ОСОБАЯ АНИМАЦИЯ ДЛЯ ЛЕГЕНДАРНОГО ПАКА! 🌟
        showLegendaryAnimation();
        
        setTimeout(() => {
            let cards = [];
            for (let i = 0; i < cardsCount; i++) {
                cards.push(getRandomCard(packType));
            }
            
            displayCards(cards);
            updateCollection(cards);
            checkSpecialCards(cards);
            
            cards.forEach(card => {
                trackCardProgress(card.id, card.rarity);
            });
        }, 3000); // Ждем 3 секунды пока анимация играет
        
    } else {
        // ОБЫЧНАЯ ЛОГИКА
        resultDiv.innerHTML = '<p style="color: white; text-align: center; font-size: 20px;">🎰 Открываем карты...</p>';
    
    setTimeout(() => {
        let cards = [];
        for (let i = 0; i < cardsCount; i++) {
            cards.push(getRandomCard(packType));
        }
        
        // Гарантированная редкая для мега пака
        if (packType === 'mega') {
            let hasRare = cards.some(card => ['epic', 'epicplus', 'mythic', 'mythicplus', 'legendary', 'legendaryplus', 's', 'splus', 'ssplus'].includes(card.rarity));
            if (!hasRare) {
                cards[0] = getRandomCard('premium');
            }
        }
        
        displayCards(cards);
        updateCollection(cards);
        checkSpecialCards(cards);
        
        // ТРЕКИНГ КАРТ ДЛЯ АЧИВОК! 🏆
        cards.forEach(card => {
            trackCardProgress(card.id, card.rarity);
        });
        
    }, 1500);
} }

function displayCards(cards) {
    let resultDiv = document.getElementById('cardResult');
    
    // ПОЛНОЭКРАННАЯ КАРТА ТОЛЬКО ДЛЯ ЛЕГЕНДАРНОГО ПАКА (1 карта)! 
    let isLegendaryCard = cards.some(card => ['s', 'splus', 'ssplus'].includes(card.rarity));
    
    if (isLegendaryCard && cards.length === 1) {
        // ПОЛНОЭКРАННАЯ КАРТА ДЛЯ ЛЕГЕНДАРНОГО ПАКА! 🔥
        document.body.style.overflow = 'hidden';
        
        let card = cards[0];
        let rarity = rarities[card.rarity];
        
        // ПОКАЗЫВАЕМ АЛЕРТЫ! 🎉
        setTimeout(() => {
            if (card.rarity === 'ssplus') {
                createConfetti();
                alert('🎉 BRILLIANT! 🎉\n' + card.name);
            } else if (card.rarity === 'splus' || card.rarity === 's') {
                alert('⭐ GREAT! ⭐\n' + card.name);
            } else if (card.rarity === 'legendary' || card.rarity === 'legendaryplus') {
                alert('LEGENDARY! \n' + card.name);
            }
        }, 4000);
        
        resultDiv.innerHTML = `
            <div style="
                position: fixed;
                top: 0;
                left: 0;
                width: 100vw;
                height: 100vh;
                background: radial-gradient(circle, ${rarity.color}20, #000000);
                z-index: 9999;
                display: flex;
                justify-content: center;
                align-items: center;
                animation: fadeIn 0.5s ease-in;
            ">
                <div style="
                    width: 400px;
                    height: 600px;
                    background: linear-gradient(45deg, ${rarity.color}, #333);
                    border: 8px solid ${rarity.color};
                    border-radius: 30px;
                    text-align: center;
                    color: white;
                    display: flex;
                    flex-direction: column;
                    justify-content: center;
                    align-items: center;
                    box-shadow: 0 0 100px ${rarity.color};
                    animation: cardGlow 2s infinite, epicScale 1s ease-out;
                    position: relative;
                ">
                    <img src="${card.image}" style="
                        width: 250px; 
                        height: 250px; 
                        object-fit: cover; 
                        border-radius: 20px; 
                        margin-bottom: 30px; 
                        border: 5px solid ${rarity.color};
                        box-shadow: 0 0 50px ${rarity.color};
                    ">
                    <div style="
                        font-size: 32px; 
                        font-weight: bold; 
                        margin-bottom: 15px; 
                        text-shadow: 4px 4px 8px black;
                    ">${card.name}</div>
                    <div style="
                        font-size: 24px; 
                        color: ${rarity.color}; 
                        font-weight: bold; 
                        text-shadow: 2px 2px 4px black;
                        animation: textGlow 1.5s infinite alternate;
                    ">${rarity.name}</div>
                    
                    <button onclick="this.parentElement.parentElement.remove(); document.body.style.overflow = 'auto';" style="
                        position: absolute;
                        bottom: 30px;
                        padding: 15px 30px;
                        background: ${rarity.color};
                        color: white;
                        border: none;
                        border-radius: 10px;
                        font-size: 18px;
                        cursor: pointer;
                        font-weight: bold;
                    ">ЗАКРЫТЬ</button>
                </div>
            </div>
        `;
        
    } else {
        // ОБЫЧНОЕ ОТОБРАЖЕНИЕ ДЛЯ ВСЕХ ОСТАЛЬНЫХ ПАКОВ
        let cardsHTML = cards.map(card => {
            let rarity = rarities[card.rarity];
            let glowClass = rarity.glow ? 'rare-card' : '';
            
            return `
                <div class="${glowClass}" style="
                    display: inline-block;
                    margin: 10px;
                    padding: 15px;
                    background: linear-gradient(45deg, ${rarity.color}, #333);
                    border: 3px solid ${rarity.color};
                    border-radius: 15px;
                    text-align: center;
                    color: white;
                    width: 150px;
                    height: 200px;
                    box-shadow: 0 0 20px ${rarity.color}50;
                    transform: scale(0.9);
                    animation: cardAppear 0.5s ease-out forwards;
                ">
                    <img src="${card.image}" style="width: 80px; height: 80px; object-fit: cover; border-radius: 8px; margin-bottom: 10px; border: 2px solid ${rarity.color};">
                    <div style="font-weight: bold; margin-bottom: 5px; text-shadow: 2px 2px 4px black;">${card.name}</div>
                    <div style="font-size: 14px; color: ${rarity.color}; font-weight: bold; text-shadow: 1px 1px 2px black;">${rarity.name}</div>
                </div>
            `;
        }).join('');
        
        resultDiv.innerHTML = cardsHTML;
    }
}



function checkSpecialCards(cards) {
    console.log('checkSpecialCards вызвана с картами:', cards);
    
    // Проверка на SS+
    let ssCards = cards.filter(card => card.rarity === 'ssplus');
    console.log('SS+ карты:', ssCards);
    if (ssCards.length > 0) {
        setTimeout(() => {
            createConfetti();
            alert('🎉 BRILLIANT! 🎉\n' + ssCards.map(c => c.name).join(', '));
        }, 3000); // Ждем 1 секунду после появления карт
    }
    
    // Проверка на S+ или S
    let sCards = cards.filter(card => card.rarity === 'splus' || card.rarity === 's');
    console.log('S/S+ карты:', sCards);
    if (sCards.length > 0 && ssCards.length === 0) {
        setTimeout(() => {
            alert('⭐ GREAT! ⭐\n' + sCards.map(c => c.name).join(', '));
        }, 3000);
    }
    
    // Проверка на Legendary+
    let legCards = cards.filter(card => card.rarity === 'legendaryplus' || card.rarity === 'legendary');
    console.log('Legendary карты:', legCards);
    if (legCards.length > 0 && ssCards.length === 0 && sCards.length === 0) {
        setTimeout(() => {
            alert('🏆 LEGENDARY! 🏆\n' + legCards.map(c => c.name).join(', '));
        }, 3000);
    }
}

function createConfetti() {
    for (let i = 0; i < 50; i++) {
        setTimeout(() => {
            let confetti = document.createElement('div');
            confetti.style.cssText = `
                position: fixed;
                left: ${Math.random() * window.innerWidth}px;
                top: ${window.innerHeight}px;
                width: 10px;
                height: 10px;
                background: ${['#FFD700', '#FF6B6B', '#4CAF50', '#2196F3', '#9C27B0'][Math.floor(Math.random() * 5)]};
                z-index: 9999;
                animation: confetti 3s ease-out forwards;
                pointer-events: none;
            `;
            document.body.appendChild(confetti);
            
            setTimeout(() => confetti.remove(), 3000);
        }, i * 50);
    }
}

function showCollection() {
    let collectedCards = Object.keys(collection);
    if (collectedCards.length === 0) {
        alert('Коллекция пуста! Открой несколько паков сначала.');
        return;
    }
    
    let collectionModal = document.createElement('div');
    collectionModal.className = 'modal';
    collectionModal.style.display = 'block';
    collectionModal.innerHTML = `
        <div class="modal-content" style="max-width: 95%; max-height: 90%;">
            <button class="close-btn" onclick="this.parentElement.parentElement.remove();">&times;</button>
            <h3>📚 Моя коллекция (${collectedCards.length}/${cardDatabase.length})</h3>
            
            <div style="display: grid; grid-template-columns: repeat(auto-fill, minmax(150px, 1fr)); gap: 15px; padding: 20px 0; max-height: 500px; overflow-y: auto;">
                ${collectedCards.map(cardId => {
                    let card = cardDatabase.find(c => c.id == cardId);
                    if (!card) return '';
                    
                    let rarity = rarities[card.rarity];
                    let count = collection[cardId];
                    
                    return `
                        <div style="
                            padding: 10px;
                            background: linear-gradient(45deg, ${rarity.color}30, #333);
                            border: 2px solid ${rarity.color};
                            border-radius: 10px;
                            text-align: center;
                            color: white;
                        ">
                            <img src="${card.image}" style="width: 60px; height: 60px; object-fit: cover; border-radius: 5px; margin-bottom: 5px;">
                            <div style="font-size: 12px; font-weight: bold;">${card.name}</div>
                            <div style="font-size: 10px; color: ${rarity.color};">${rarity.name}</div>
                            <div style="font-size: 10px; color: #ccc;">x${count}</div>
                        </div>
                    `;
                }).join('')}
            </div>
        </div>
    `;
    document.body.appendChild(collectionModal);
}

function updateCollection(newCards) {
    newCards.forEach(card => {
        if (!collection[card.id]) {
            collection[card.id] = 0;
        }
        collection[card.id]++;
    });
    
    updateUI();
}

function saveProgress() {
    let gameData = {
        cardMoney: cardMoney,
        collection: collection,
        clickPower: clickPower,
        totalClicks: totalClicks,
        hasAutoClick: hasAutoClick
    };
    localStorage.setItem('forsaken_cards', JSON.stringify(gameData));
    alert('💾 Прогресс сохранен!');
}

function loadProgress() {
    let saved = localStorage.getItem('forsaken_cards');
    if (saved) {
        let gameData = JSON.parse(saved);
        cardMoney = gameData.cardMoney || 0;
        collection = gameData.collection || {};
        clickPower = gameData.clickPower || 1;
        totalClicks = gameData.totalClicks || 0;
        hasAutoClick = gameData.hasAutoClick || false;
        
        if (hasAutoClick) {
            startAutoClick();
        }
        
        updateUI();
    }
}

// Добавляем игру в меню
