function updateVisitorCounter() {
    let visitors = localStorage.getItem('forsaken_visitors');
    
    if (!visitors) {
        visitors = 1;
    } else {
        visitors = parseInt(visitors) + 1;
    }
    
    localStorage.setItem('forsaken_visitors', visitors);
    document.getElementById('visitorCount').textContent = visitors;
}

