// Функция загрузки достижений
function loadAchievements() {
    let saved = localStorage.getItem('forsaken_achievements');
    if (saved) {
        let savedAchievements = JSON.parse(saved);
        // Обновляем статус достижений
        Object.keys(achievementsDatabase).forEach(category => {
            achievementsDatabase[category].forEach(achievement => {
                if (savedAchievements[achievement.id]) {
                    achievement.unlocked = true;
                }
            });
        });
    }
    
    displayAchievements();
    updateProgress();
}

// ФУНКЦИИ ПЕРЕКЛЮЧЕНИЯ ТАБОВ
function showSiteAchievements() {
    // Показать контейнер сайта
    document.getElementById('siteAchievementsContainer').style.display = 'block';
    document.getElementById('gameAchievementsContainer').style.display = 'none';
    
    // Стили активной кнопки для сайта
    document.getElementById('siteTab').style.background = 'linear-gradient(45deg, #ff6b6b, #ffa500)';
    document.getElementById('siteTab').style.border = 'none';
    document.getElementById('siteTab').style.boxShadow = '0 4px 15px rgba(255, 107, 107, 0.4)';
    
    // Стили неактивной кнопки для игры
    document.getElementById('gameTab').style.background = 'rgba(255, 255, 255, 0.1)';
    document.getElementById('gameTab').style.border = '2px solid #ff6b6b';
    document.getElementById('gameTab').style.boxShadow = 'none';
}

function showGameAchievements() {
    // Показать контейнер игры
    document.getElementById('siteAchievementsContainer').style.display = 'none';
    document.getElementById('gameAchievementsContainer').style.display = 'block';
    
    // Стили активной кнопки для игры
    document.getElementById('gameTab').style.background = 'linear-gradient(45deg, #ff6b6b, #ffa500)';
    document.getElementById('gameTab').style.border = 'none';
    document.getElementById('gameTab').style.boxShadow = '0 4px 15px rgba(255, 107, 107, 0.4)';
    
    // Стили неактивной кнопки для сайта
    document.getElementById('siteTab').style.background = 'rgba(255, 255, 255, 0.1)';
    document.getElementById('siteTab').style.border = '2px solid #ff6b6b';
    document.getElementById('siteTab').style.boxShadow = 'none';
}

// ОБНОВЛЕННАЯ ФУНКЦИЯ ОТОБРАЖЕНИЯ
function displayAchievements() {
    // ДОСТИЖЕНИЯ САЙТА
    let siteContainer = document.getElementById('siteAchievements');
    if (siteContainer && achievementsDatabase.site) {
        siteContainer.innerHTML = achievementsDatabase.site
    .filter(achievement => achievement.type !== 'hidden' || achievement.unlocked)
    .map(achievement => {
            let isUnlockable = achievement.type === 'unlockable';
            return `
                <div class="achievement-card ${achievement.unlocked ? 'unlocked' : 'locked'}" style="
                    background: ${achievement.unlocked ? 'rgba(76, 175, 80, 0.2)' : 'rgba(100, 100, 100, 0.2)'};
                    border: 2px solid ${achievement.unlocked ? '#4CAF50' : '#666'};
                    border-radius: 10px;
                    padding: 15px;
                    margin: 10px;
                    text-align: center;
                    color: white;
                    opacity: ${achievement.unlocked ? '1' : '0.6'};
                ">
                    <div style="font-size: 30px;">${achievement.icon}</div>
                    <h5 style="margin: 10px 0 5px 0;">${achievement.name}</h5>
                    <p style="margin: 0; font-size: 12px;">${achievement.desc}</p>
                    ${achievement.unlocked ? 
                        '<div style="color: #4CAF50; font-weight: bold;">✅ РАЗБЛОКИРОВАНО</div>' : 
                        '<div style="color: #999;">🔒 ЗАБЛОКИРОВАНО</div>'}
                </div>
            `;
        }).join('');
    }
    
    // ДОСТИЖЕНИЯ ИГРЫ
    let gameContainer = document.getElementById('gameAchievements');
    if (gameContainer && achievementsDatabase.game) {
        gameContainer.innerHTML = achievementsDatabase.game.map(achievement => {
            return `
                <div class="achievement-card info-only" style="
                    background: rgba(100, 100, 150, 0.2);
                    border: 2px solid #6666AA;
                    border-radius: 10px;
                    padding: 15px;
                    margin: 10px;
                    text-align: center;
                    color: white;
                    opacity: 0.8;
                ">
                    <div style="font-size: 30px;">${achievement.icon}</div>
                    <h5 style="margin: 10px 0 5px 0;">${achievement.name}</h5>
                    <p style="margin: 0; font-size: 12px;">${achievement.desc}</p>
                    <div style="color: #6666AA; font-weight: bold;">ℹ️ ИЗ ИГРЫ FORSAKEN</div>
                </div>
            `;
        }).join('');
    }
}

// ОБНОВЛЕННАЯ ФУНКЦИЯ ПРОГРЕССА (ТОЛЬКО ДЛЯ САЙТА)
function updateProgress() {
    // СЧИТАЕМ ТОЛЬКО ВИДИМЫЕ АЧИВКИ!
    let visibleSiteAchievements = achievementsDatabase.site.filter(achievement => 
        achievement.type !== 'hidden' || achievement.unlocked
    );
    
    let totalSiteAchievements = visibleSiteAchievements.length;
    let unlockedSiteAchievements = visibleSiteAchievements.filter(achievement => 
        achievement.unlocked
    ).length;
    
    let percentage = totalSiteAchievements > 0 ? Math.round((unlockedSiteAchievements / totalSiteAchievements) * 100) : 0;
    
    let progressElement = document.getElementById('totalProgress');
    let progressBarElement = document.getElementById('progressBar');
    
    if (progressElement) {
        progressElement.textContent = `${unlockedSiteAchievements}/${totalSiteAchievements} (${percentage}%)`;
    }
    
    if (progressBarElement) {
        progressBarElement.style.width = percentage + '%';
    }
}

// Проверка времени 3:33
function checkInsomniaAchievement() {
    let now = new Date();
    if (now.getHours() === 3 && now.getMinutes() === 33) {
        unlockAchievement('insomnia');
    }
}

// Проверка времени на сайте
let siteStartTime = Date.now();
function checkMarathonAchievement() {
    let timeSpent = Date.now() - siteStartTime;
    if (timeSpent >= 7200000) { // 2 часа в миллисекундах
        unlockAchievement('marathon_user');
    }
}

// Проверка ежедневных визитов
function checkLoyalFanAchievement() {
    let visits = JSON.parse(localStorage.getItem('daily_visits') || '[]');
    let today = new Date().toDateString();
    
    if (!visits.includes(today)) {
        visits.push(today);
        localStorage.setItem('daily_visits', JSON.stringify(visits));
    }
    
    // Проверяем последние 7 дней
    let last7Days = [];
    for (let i = 0; i < 7; i++) {
        let date = new Date();
        date.setDate(date.getDate() - i);
        last7Days.push(date.toDateString());
    }
    
    let consecutiveDays = last7Days.every(day => visits.includes(day));
    if (consecutiveDays) {
        unlockAchievement('loyal_fan');
    }
}

// Музыкальные ачивки
let musicStats = {
    totalListenTime: 0,
    trackPlays: {},
    allTracksCompleted: false
};

function trackMusicProgress(trackName, duration, completed) {
    if (!musicStats.trackPlays[trackName]) {
        musicStats.trackPlays[trackName] = 0;
    }
    
    if (completed) {
        musicStats.trackPlays[trackName]++;
        musicStats.totalListenTime += duration;
        
        // Проверка фанатика звука (10 раз каждый трек)
        let allTracksPlayed10Times = Object.values(musicStats.trackPlays).every(count => count >= 10);
        if (allTracksPlayed10Times) {
            unlockAchievement('sound_fanatic');
        }
        
        // Проверка истинного меломана (все треки один раз)
        let trackNames = ['playtime.mp3', 'deep_sleep.mp3', 'a_tight_squeeze.mp3'];
        let allTracksPlayed = trackNames.every(track => musicStats.trackPlays[track] >= 1);
        if (allTracksPlayed) {
            unlockAchievement('true_meloman');
        }
    }
    
    // Проверка ночного диджея (30 минут)
    if (musicStats.totalListenTime >= 1800000) { // 30 минут
        unlockAchievement('night_dj');
    }
}

// Карточные ачивки
let cardStats = {
    packsOpened: 0,
    packOpenTime: null,
    collectedCards: new Set(),
    ssCards: 0
};

function trackCardProgress(cardId, rarity) {
    cardStats.collectedCards.add(cardId);
    
    if (rarity === 'ssplus') {
        cardStats.ssCards++;
        if (cardStats.ssCards >= 1) {
            unlockAchievement('legendary_luck');
        }
    }
    
    // Полная коллекция
    if (cardStats.collectedCards.size >= 221) {
        unlockAchievement('full_collection');
    }
}

function trackPackOpening() {
    cardStats.packsOpened++;
    
    if (!cardStats.packOpenTime) {
        cardStats.packOpenTime = Date.now();
    }
    
    // 250 паков подряд
    if (cardStats.packsOpened >= 250) {
        unlockAchievement('patient_collector');
    }
    
    // 30 минут открытия паков
    let timePassed = Date.now() - cardStats.packOpenTime;
    if (timePassed >= 1800000 && cardStats.packsOpened >= 10) {
        unlockAchievement('luck_marathon');
    }
}

// Игровые ачивки
function trackGameProgress(gameType, achievement) {
    if (gameType === 'tower_defense' && achievement === 'wave_12') {
        unlockAchievement('defender');
    }
    if (gameType === 'first_game' && achievement === 'killed_1x1x1x1') {
        unlockAchievement('unit_killer');
    }
}

// ИНИЦИАЛИЗАЦИЯ ПРИ ЗАГРУЗКЕ
window.onload = function() {
    updateVisitorCounter();
    checkFirstVisit();
    checkInsomniaAchievement();
    checkLoyalFanAchievement();
    
    // ДОБАВЬ ЭТУ СТРОКУ!
    checkSpectreUnlock();
    
    // Проверка марафона каждые 10 секунд
    setInterval(checkMarathonAchievement, 10000);
    
    // Сброс статистики паков при закрытии сайта
    window.addEventListener('beforeunload', function() {
        cardStats.packsOpened = 0;
        cardStats.packOpenTime = null;
    });
};

// ИСПРАВЛЕННАЯ ФУНКЦИЯ unlockAchievement
function unlockAchievement(achievementId) {
    let found = false;
    Object.keys(achievementsDatabase).forEach(category => {
        achievementsDatabase[category].forEach(achievement => {
            if (achievement.id === achievementId && !achievement.unlocked) {
                achievement.unlocked = true;
                found = true;
                
                // Сохраняем в localStorage
                let saved = JSON.parse(localStorage.getItem('forsaken_achievements') || '{}');
                saved[achievementId] = true;
                localStorage.setItem('forsaken_achievements', JSON.stringify(saved));
                
                // РАЗБЛОКИРОВКА СПЕКТРА!
                if (achievementId === 'forbidden_knowledge') {
                    unlockSpectreSection();
                }
                
                showAchievementNotification(achievement);
            }
        });
    });
    return found;
}

// Уведомление о достижении
function showAchievementNotification(achievement) {
    // ЗВУК АЧИВКИ
    let achievementSound = new Audio('steam-achievement.mp3'); // или другой звук
    achievementSound.volume = 0.7;
    achievementSound.play().catch(e => console.log('Звук не загрузился:', e));
    
    let notification = document.createElement('div');
    notification.style.cssText = `
        position: fixed;
        top: 20px;
        right: -400px;
        background: ${achievement.type === 'hidden' ? 'linear-gradient(45deg, #9C27B0, #7B1FA2)' : 'linear-gradient(45deg, #4CAF50, #45a049)'};
        color: white;
        padding: 20px;
        border-radius: 10px;
        box-shadow: ${achievement.type === 'hidden' ? '0 0 30px rgba(156, 39, 176, 0.8)' : '0 0 30px rgba(76, 175, 80, 0.8)'};
        z-index: 10000;
        border: 2px solid #FFD700;
        min-width: 300px;
        transition: right 0.5s ease-out;
    `;
    notification.innerHTML = `
        <div style="display: flex; align-items: center; gap: 15px;">
            <div style="font-size: 40px;">${achievement.icon}</div>
            <div>
                <div style="font-size: 12px; opacity: 0.8;">ДОСТИЖЕНИЕ РАЗБЛОКИРОВАНО</div>
                <div style="font-weight: bold; font-size: 16px;">${achievement.name}</div>
                <div style="font-size: 12px; opacity: 0.9;">${achievement.desc}</div>
            </div>
        </div>
    `;

    document.body.appendChild(notification);
    
    // АНИМАЦИЯ ПОЯВЛЕНИЯ
    setTimeout(() => {
        notification.style.right = '20px';
    }, 100);
    
    // АНИМАЦИЯ ИСЧЕЗНОВЕНИЯ
    setTimeout(() => {
        notification.style.right = '-400px';
        setTimeout(() => notification.remove(), 500);
    }, 4000);
}

