function addScaryArtifacts(container) {
    // Добавляем случайные жуткие артефакты
    for (let i = 0; i < 3; i++) {
        let artifact = document.createElement('div');
        artifact.style.cssText = `
            position: absolute;
            top: ${Math.random() * 80}%;
            left: ${Math.random() * 80}%;
            width: ${10 + Math.random() * 20}px;
            height: 2px;
            background: #ff0000;
            animation: artifactGlitch 0.5s ease-out;
        `;
        container.appendChild(artifact);
        
        setTimeout(() => artifact.remove(), 500);
    }
}

function unlockSpectreSection() {
    let spectreSection = document.getElementById('spectreSection');
    if (spectreSection) {
        // Убираем класс "locked"
        spectreSection.classList.remove('locked');
        
        // Убираем цепи с анимацией
        let chains = document.getElementById('spectreChains');
        if (chains) {
            chains.style.animation = 'chainBreak 1s ease-out forwards';
            setTimeout(() => {
                chains.style.display = 'none'; // или chains.remove();
            }, 1000);
        }
        
        // Меняем описание
        let desc = spectreSection.querySelector('p');
        if (desc) {
            desc.textContent = 'Истинная история...';
            desc.style.color = '#ff6b6b';
        }
    }
}

// Добавь в конец script.js
function addMobileSupport() {
    // Проверяем, мобильное ли устройство
    const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
    
    if (isMobile) {
        // Убираем hover-эффекты на мобилках
        document.body.classList.add('mobile-device');
        
        // Добавляем тач-события для Спектра
        let spectreSection = document.getElementById('spectreSection');
        if (spectreSection) {
            let touchTimer;
            
            spectreSection.addEventListener('touchstart', function() {
                if (!spectreSection.classList.contains('locked')) {
                    touchTimer = setTimeout(() => {
                        // Запускаем глитч-эффект на долгое нажатие
                        spectreSection.classList.add('mobile-glitch');
                        setTimeout(() => {
                            spectreSection.classList.remove('mobile-glitch');
                        }, 1000);
                    }, 500);
                }
            });
            
            spectreSection.addEventListener('touchend', function() {
                clearTimeout(touchTimer);
            });
        }
    }
}

// Вызываем при загрузке
window.addEventListener('load', addMobileSupport);